func (t *sessionTerminal) scheduleIdleCloseLocked() {
	if t.idleTimer != nil {
		t.idleTimer.Stop()
	}

	if t.idleDelay <= 0 {
		go func() {
			_ = t.close()
		}()
		return
	}

	t.idleTimer = time.AfterFunc(t.idleDelay, func() {
		_ = t.close()
	})
