	t.mu.Lock()
	defer t.mu.Unlock()

	copied := append([]byte(nil), chunk...)
	t.scroll = append(t.scroll, copied...)
	if overflow := len(t.scroll) - t.maxScroll; overflow > 0 {
		t.scroll = append([]byte(nil), t.scroll[overflow:]...)
	}

	for client := range t.clients {
		select {
		case client <- copied:
		default:
		}
	}
