	select {
	case <-t.done:
		return true
	default:
		return false
	}
}

func (t *sessionTerminal) close() error {
	err := t.process.Close()
	t.finish(err)
	return err
}

func (t *sessionTerminal) finish(err error) {
	t.doneOnce.Do(func() {
		t.mu.Lock()
		if t.idleTimer != nil {
			t.idleTimer.Stop()
			t.idleTimer = nil
		}
		t.exitErr = err
