func (p *WorkspaceProvider) attachCommand(ctx context.Context, runtimeKind string, runtimeTarget string) ([]string, bool) {
	if runtimeTarget == "" || runtime.GOOS == "windows" {
		return nil, false
	}

	switch runtimeKind {
	case "zellij":
		zellijPath := p.zellijPath()
		if zellijPath == "" || !p.hasZellijSession(ctx, runtimeTarget) {
			return nil, false
		}

		return []string{zellijPath, "attach", runtimeTarget}, true
	case "tmux":
		tmuxPath := p.tmuxPath()
		if tmuxPath == "" || !p.hasTmuxSession(ctx, runtimeTarget) {
			return nil, false
		}

		return tmuxAttachCommand(tmuxPath, runtimeTarget), true
	default:
		return nil, false
	}
}

func tmuxAttachCommand(tmuxPath string, target string) []string {
	targetArg := "=" + target
	shellPath := posixShellPath()
	if shellPath == "" {
		return []string{tmuxPath, "attach-session", "-t", targetArg}
	}

	command := fmt.Sprintf(
		"%s capture-pane -e -p -S -%d -t %s 2>/dev/null || true; exec %s attach-session -t %s",
		shellQuote(tmuxPath),
		tmuxScrollbackCaptureLines,
		shellQuote(targetArg),
		shellQuote(tmuxPath),
		shellQuote(targetArg),
	)

	return []string{shellPath, "-lc", command}
}

func posixShellPath() string {
	for _, candidate := range []string{"/bin/sh", "/usr/bin/sh"} {
		if _, err := os.Stat(candidate); err == nil {
			return candidate
		}
	}

	if path, err := exec.LookPath("sh"); err == nil {
		return path
	}

	return ""
}

func shellQuote(value string) string {
	return "'" + strings.ReplaceAll(value, "'", "'\\''") + "'"
}

func (p *WorkspaceProvider) hasTmuxSession(ctx context.Context, target string) bool {
	if p.TmuxHasSession != nil {
		return p.TmuxHasSession(ctx, target)
	}

	tmuxPath := p.tmuxPath()
	if tmuxPath == "" {
		return false
	}

	probeCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
	defer cancel()

	cmd := exec.CommandContext(probeCtx, tmuxPath, "has-session", "-t", "="+target)
	return cmd.Run() == nil
}

func (p *WorkspaceProvider) tmuxPath() string {
	if p.TmuxPath != "" {
		return p.TmuxPath
	}

	for _, candidate := range []string{
		"/opt/homebrew/bin/tmux",
		"/usr/local/bin/tmux",
		"/usr/bin/tmux",
	} {
		if _, err := os.Stat(candidate); err == nil {
			p.TmuxPath = candidate
			return candidate
		}
	}

	if path, err := exec.LookPath("tmux"); err == nil {
		p.TmuxPath = path
		return path
	}

	return ""
}

func (p *WorkspaceProvider) hasZellijSession(ctx context.Context, target string) bool {
	if p.ZellijHasSession != nil {
		return p.ZellijHasSession(ctx, target)
	}

	zellijPath := p.zellijPath()
	if zellijPath == "" {
		return false
	}

	probeCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
	defer cancel()

	cmd := exec.CommandContext(probeCtx, zellijPath, "list-sessions", "--short", "--no-formatting")
	output, err := cmd.Output()
	if err != nil {
		return false
	}

	for _, line := range strings.Split(string(output), "\n") {
		if strings.TrimSpace(line) == target {
			return true
		}
	}

	return false
}

func (p *WorkspaceProvider) zellijPath() string {
	if p.ZellijPath != "" {
		return p.ZellijPath
	}

	candidates := []string{
		"/opt/homebrew/bin/zellij",
		"/usr/local/bin/zellij",
		"/usr/bin/zellij",
		"/run/current-system/sw/bin/zellij",
	}
	if home, err := os.UserHomeDir(); err == nil {
		candidates = append(candidates, filepath.Join(home, ".nix-profile", "bin", "zellij"))
	}
	if user := os.Getenv("USER"); user != "" {
		candidates = append(candidates, filepath.Join("/etc/profiles/per-user", user, "bin", "zellij"))
	}

	for _, candidate := range candidates {
		if _, err := os.Stat(candidate); err == nil {
			p.ZellijPath = candidate
			return candidate
		}
	}

	if path, err := exec.LookPath("zellij"); err == nil {
		p.ZellijPath = path
		return path
	}

	return ""
}

func (p *WorkspaceProvider) baseDir() (string, error) {
	if p.BaseDir != "" {
		return p.BaseDir, nil
	}

	home, err := os.UserHomeDir()
	if err != nil {
		return "", fmt.Errorf("resolve user home: %w", err)
	}

	return filepath.Join(home, ".agent-orchestrator"), nil
}

func readRunningFile(path string) (runningFile, error) {
	var running runningFile
	data, err := os.ReadFile(path)
	if err != nil {
		return runningFile{}, err
	}
	if err := json.Unmarshal(data, &running); err != nil {
		return runningFile{}, fmt.Errorf("decode AO running file: %w", err)
	}

	return running, nil
}

func readSessionMetadata(path string) (sessionMetadata, error) {
	var meta sessionMetadata
	data, err := os.ReadFile(path)
	if err != nil {
		return meta, err
	}
	if err := json.Unmarshal(data, &meta); err != nil {
		return meta, fmt.Errorf("decode AO session metadata %s: %w", path, err)
	}
	if info, err := os.Stat(path); err == nil {
		meta.modifiedAt = info.ModTime()
	}

	return meta, nil
}

func listProjectIDs(projectsDir string) []string {
	entries, err := os.ReadDir(projectsDir)
	if err != nil {
		return nil
	}

	projectIDs := make([]string, 0, len(entries))
	for _, entry := range entries {
		if entry.IsDir() {
			projectIDs = append(projectIDs, entry.Name())
		}
	}
	sort.Strings(projectIDs)
	return projectIDs
}

func emptyWorkspace() session.Workspace {
	return session.Workspace{
		ActiveProjectID: "local",
		Projects: []session.Project{
			{ID: "local", Name: "Local"},
		},
		Sessions: []session.Session{},
	}
}

func firstRuntimeHandle(meta sessionMetadata) runtimeHandle {
	if meta.Lifecycle.Runtime.Handle.RuntimeName != "" || meta.Lifecycle.Runtime.Handle.ID != "" {
		return meta.Lifecycle.Runtime.Handle
	}

	return meta.RuntimeHandle
}

func sessionRuntimeTarget(meta sessionMetadata, handle runtimeHandle, pipePath string) string {
	switch handle.RuntimeName {
	case "zellij":
		return firstNonEmpty(
			stringFromMap(handle.Data, "sessionName"),
			stringFromMap(handle.Data, "session"),
			handle.ID,
		)
	default:
		return firstNonEmpty(meta.TmuxName, meta.Lifecycle.Runtime.Tmux, handle.ID, pipePath)
	}
}

func isOrchestrator(id string, meta sessionMetadata) bool {
	if meta.Role == "worker" || meta.Lifecycle.Session.Kind == "worker" {
