		id == "orchestrator" ||
		strings.HasSuffix(id, "-orchestrator") ||
		regexp.MustCompile(`-orchestrator-\d+$`).MatchString(id)
}

func isTerminal(meta sessionMetadata) bool {
	sessionState := meta.Lifecycle.Session.State
