	defer cancel()

	client := make(chan []byte, clientBufferChunks)
	replay := t.addClient(client)
	defer t.removeClient(client)

	writerDone := make(chan error, 1)
	go func() {
		writerDone <- t.writeToConn(ctx, conn, replay, client)
