            issue: '[PR #1]',
            metadata: '[codex/working]',
            project: 'agent-orchestrator_live',
            selected: true,
            state: 'working',
            terminalSupported: true,
            title: 'Live worker',
            workerId: '[AO-LIVE]',
          },
        ],
      }),
      contentType: 'application/json',
      status: 200,
    });
  });

  await page.goto('/');
  await expect(
    page.getByRole('button', { name: '[AO-LIVE] Live worker' })
  ).toBeVisible({
    timeout: 15_000,
  });

  await page.getByRole('tab', { name: 'Terminal' }).click();
